+        assert_eq!(stats.peak_us, 1200);
+        assert_eq!(stats.query_count, 2);
+        stats.record(300);
+        assert_eq!(stats.last_query_us, 300);
+        assert_eq!(stats.peak_us, 1200); // peak unchanged
